import { useMemo, useState } from "react";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);
    const [file, setFile] = useState(null);
    const [fileName, setFileName] = useState("");
    const [loading, setLoading] = useState(false);
    const [uploadMessage, setUploadMessage] = useState("");
    const [darkMode, setDarkMode] = useState(false);

    const theme = useMemo(() => {
        return darkMode
            ? {
                pageBg: "linear-gradient(135deg, #0f172a, #1e293b)",
                cardBg: "#111827",
                text: "#f9fafb",
                subText: "#cbd5e1",
                border: "#334155",
                inputBg: "#0f172a",
                inputText: "#f9fafb",
                sectionBg: "#1f2937",
                mutedTagBg: "#374151",
                mutedTagText: "#e5e7eb",
                matchedBg: "#14532d",
                matchedText: "#dcfce7",
                missingBg: "#7f1d1d",
                missingText: "#fee2e2",
                infoBg: "#172554",
                infoText: "#dbeafe",
                successBg: "#052e16",
                successText: "#dcfce7",
                progressBg: "#334155",
                shadow: "0 10px 30px rgba(0,0,0,0.35)"
            }
            : {
                pageBg: "linear-gradient(135deg, #eef2ff, #f8fafc)",
                cardBg: "#ffffff",
                text: "#111827",
                subText: "#475569",
                border: "#dbe4ee",
                inputBg: "#ffffff",
                inputText: "#111827",
                sectionBg: "#f8fafc",
                mutedTagBg: "#e5e7eb",
                mutedTagText: "#374151",
                matchedBg: "#dcfce7",
                matchedText: "#166534",
                missingBg: "#fee2e2",
                missingText: "#991b1b",
                infoBg: "#dbeafe",
                infoText: "#1e3a8a",
                successBg: "#dcfce7",
                successText: "#166534",
                progressBg: "#e5e7eb",
                shadow: "0 10px 30px rgba(15,23,42,0.12)"
            };
    }, [darkMode]);

    const analyzeResume = async () => {
        if (!resumeText.trim()) {
            setAnalysis({
                role: "Unknown",
                score: 0,
                requiredKeywords: [],
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Please paste or upload a resume first."]
            });
            return;
        }

        setLoading(true);
        setUploadMessage("");

        try {
            const res = await fetch("http://localhost:5000/analyze", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({ resumeText, jobDescription })
            });

            const data = await res.json();
            setAnalysis(data);
        } catch (error) {
            setAnalysis({
                role: "Unknown",
                score: 0,
                requiredKeywords: [],
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Could not connect to backend."]
            });
        } finally {
            setLoading(false);
        }
    };

    const uploadResume = async () => {
        if (!file) {
            setUploadMessage("Please select a PDF first.");
            return;
        }

        setLoading(true);
        setUploadMessage("");
        setAnalysis(null);

        try {
            const formData = new FormData();
            formData.append("resume", file);

            const res = await fetch("http://localhost:5000/upload", {
                method: "POST",
                body: formData
            });

            const data = await res.json();

            if (data.extractedText) {
                setResumeText(data.extractedText);
            }

            setUploadMessage(data.message || "Resume extracted successfully.");
        } catch (error) {
            setUploadMessage("Error uploading PDF.");
        } finally {
            setLoading(false);
        }
    };

    const getScoreColor = (score) => {
        if (score >= 75) return "#22c55e";
        if (score >= 50) return "#f59e0b";
        return "#ef4444";
    };

    const getScoreMessage = (score) => {
        if (score >= 80) return "Strong alignment with the job description.";
        if (score >= 60) return "Decent match, but there are gaps to improve.";
        if (score >= 40) return "Partial match. Resume needs better alignment.";
        return "Low match. Important skills are missing or not highlighted.";
    };

    const getAiExplanation = () => {
        if (!analysis) return "";

        const matchedCount = analysis.matchedSkills?.length || 0;
        const missingCount = analysis.missingSkills?.length || 0;
        const requiredCount = analysis.requiredKeywords?.length || 0;

        if (!jobDescription.trim()) {
            return "This score is based mostly on skills found in your resume, plus small bonus points for projects, internships, and GitHub.";
        }

        return `Your score is ${analysis.score}/100 because ${matchedCount} out of ${requiredCount} key JD keywords were matched in the resume. ${
            missingCount > 0
                ? `The biggest gaps are: ${analysis.missingSkills.slice(0, 5).join(", ")}.`
                : "There are no major missing keywords detected from the JD."
        }`;
    };

    const downloadReport = () => {
        if (!analysis) return;

        const lines = [
            "AI Resume Analyzer Report",
            "=========================",
            "",
            `Role: ${analysis.role || "Unknown"}`,
            `Score: ${analysis.score}/100`,
            "",
            "Required Keywords:",
            ...(analysis.requiredKeywords?.length ? analysis.requiredKeywords : ["None"]),
            "",
            "Matched Skills:",
            ...(analysis.matchedSkills?.length ? analysis.matchedSkills : ["None"]),
            "",
            "Missing Skills:",
            ...(analysis.missingSkills?.length ? analysis.missingSkills : ["None"]),
            "",
            "Suggestions:",
            ...(analysis.suggestions?.length ? analysis.suggestions : ["None"]),
            "",
            "AI Explanation:",
            getAiExplanation()
        ];

        const blob = new Blob([lines.join("\n")], { type: "text/plain;charset=utf-8" });
        const url = URL.createObjectURL(blob);

        const link = document.createElement("a");
        link.href = url;
        link.download = "resume-analysis-report.txt";
        document.body.appendChild(link);
        link.click();
        link.remove();
        URL.revokeObjectURL(url);
    };

    const tagStyle = (bg, color) => ({
        display: "inline-block",
        padding: "8px 12px",
        borderRadius: "999px",
        margin: "6px",
        fontSize: "14px",
        fontWeight: "600",
        background: bg,
        color: color,
        border: "1px solid transparent",
        transform: "translateY(0px)",
        transition: "all 0.2s ease"
    });

    const buttonBase = {
        border: "none",
        borderRadius: "10px",
        padding: "12px 18px",
        cursor: "pointer",
        fontSize: "15px",
        fontWeight: "600",
        transition: "all 0.2s ease"
    };

    return (
        <div
            style={{
                minHeight: "100vh",
                background: theme.pageBg,
                padding: "28px",
                fontFamily: "Inter, Arial, sans-serif",
                color: theme.text
            }}
        >
            <div
                style={{
                    maxWidth: "980px",
                    margin: "0 auto",
                    background: theme.cardBg,
                    borderRadius: "20px",
                    boxShadow: theme.shadow,
                    padding: "28px",
                    border: `1px solid ${theme.border}`
                }}
            >
                <div
                    style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        gap: "16px",
                        flexWrap: "wrap",
                        marginBottom: "12px"
                    }}
                >
                    <div>
                        <h1 style={{ margin: 0, fontSize: "32px" }}>AI Resume Analyzer 🚀</h1>
                        <p style={{ marginTop: "8px", color: theme.subText }}>
                            Upload a PDF or paste your resume, then compare it against any job description.
                        </p>
                    </div>

                    <button
                        onClick={() => setDarkMode((prev) => !prev)}
                        style={{
                            ...buttonBase,
                            background: darkMode ? "#f8fafc" : "#0f172a",
                            color: darkMode ? "#0f172a" : "#f8fafc"
                        }}
                    >
                        {darkMode ? "☀ Light Mode" : "🌙 Dark Mode"}
                    </button>
                </div>

                <div
                    style={{
                        background: theme.sectionBg,
                        borderRadius: "16px",
                        padding: "18px",
                        marginTop: "18px",
                        border: `1px solid ${theme.border}`
                    }}
                >
                    <h3 style={{ marginTop: 0 }}>Upload Resume (PDF)</h3>
                    <div style={{ display: "flex", gap: "12px", flexWrap: "wrap", alignItems: "center" }}>
                        <input
                            type="file"
                            accept=".pdf"
                            onChange={(e) => {
                                setFile(e.target.files[0]);
                                setFileName(e.target.files[0]?.name || "");
                            }}
                            style={{
                                color: theme.text
                            }}
                        />

                        <button
                            onClick={uploadResume}
                            style={{
                                ...buttonBase,
                                background: "#16a34a",
                                color: "#ffffff"
                            }}
                        >
                            {loading ? "Uploading..." : "Upload & Extract"}
                        </button>
                    </div>

                    {fileName && (
                        <p style={{ marginTop: "10px", color: theme.subText }}>
                            Selected file: <strong>{fileName}</strong>
                        </p>
                    )}

                    {uploadMessage && (
                        <div
                            style={{
                                marginTop: "12px",
                                background: theme.successBg,
                                color: theme.successText,
                                borderRadius: "10px",
                                padding: "12px 14px"
                            }}
                        >
                            {uploadMessage}
                        </div>
                    )}
                </div>

                <div
                    style={{
                        display: "grid",
                        gridTemplateColumns: "1fr",
                        gap: "18px",
                        marginTop: "18px"
                    }}
                >
                    <div
                        style={{
                            background: theme.sectionBg,
                            borderRadius: "16px",
                            padding: "18px",
                            border: `1px solid ${theme.border}`
                        }}
                    >
                        <h3 style={{ marginTop: 0 }}>Resume</h3>
                        <textarea
                            value={resumeText}
                            onChange={(e) => setResumeText(e.target.value)}
                            placeholder="Paste resume here..."
                            style={{
                                width: "100%",
                                minHeight: "160px",
                                resize: "vertical",
                                borderRadius: "12px",
                                border: `1px solid ${theme.border}`,
                                padding: "14px",
                                fontSize: "14px",
                                lineHeight: 1.5,
                                background: theme.inputBg,
                                color: theme.inputText,
                                outline: "none",
                                boxSizing: "border-box"
                            }}
                        />
                    </div>

                    <div
                        style={{
                            background: theme.sectionBg,
                            borderRadius: "16px",
                            padding: "18px",
                            border: `1px solid ${theme.border}`
                        }}
                    >
                        <h3 style={{ marginTop: 0 }}>Job Description</h3>
                        <textarea
                            value={jobDescription}
                            onChange={(e) => setJobDescription(e.target.value)}
                            placeholder="Paste job description here..."
                            style={{
                                width: "100%",
                                minHeight: "160px",
                                resize: "vertical",
                                borderRadius: "12px",
                                border: `1px solid ${theme.border}`,
                                padding: "14px",
                                fontSize: "14px",
                                lineHeight: 1.5,
                                background: theme.inputBg,
                                color: theme.inputText,
                                outline: "none",
                                boxSizing: "border-box"
                            }}
                        />
                    </div>
                </div>

                <div
                    style={{
                        display: "flex",
                        gap: "12px",
                        flexWrap: "wrap",
                        justifyContent: "center",
                        marginTop: "18px"
                    }}
                >
                    <button
                        onClick={analyzeResume}
                        style={{
                            ...buttonBase,
                            background: "#2563eb",
                            color: "#ffffff",
                            minWidth: "160px"
                        }}
                    >
                        {loading ? "Analyzing..." : "Analyze Match"}
                    </button>

                    <button
                        onClick={downloadReport}
                        disabled={!analysis}
                        style={{
                            ...buttonBase,
                            background: analysis ? "#7c3aed" : "#94a3b8",
                            color: "#ffffff",
                            minWidth: "170px",
                            cursor: analysis ? "pointer" : "not-allowed"
                        }}
                    >
                        Download Report
                    </button>
                </div>

                {analysis && (
                    <div style={{ marginTop: "24px" }}>
                        <div
                            style={{
                                display: "grid",
                                gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
                                gap: "16px",
                                marginBottom: "16px"
                            }}
                        >
                            <InfoCard
                                title="Detected Role"
                                value={analysis.role || "Unknown"}
                                theme={theme}
                            />
                            <InfoCard
                                title="Match Quality"
                                value={getScoreMessage(analysis.score)}
                                theme={theme}
                            />
                        </div>

                        <div
                            style={{
                                background: theme.infoBg,
                                color: theme.infoText,
                                borderRadius: "16px",
                                padding: "18px",
                                marginBottom: "16px"
                            }}
                        >
                            <h3 style={{ marginTop: 0 }}>Score: {analysis.score}/100</h3>
                            <div
                                style={{
                                    height: "18px",
                                    background: theme.progressBg,
                                    borderRadius: "999px",
                                    overflow: "hidden",
                                    marginTop: "10px"
                                }}
                            >
                                <div
                                    style={{
                                        width: `${analysis.score}%`,
                                        height: "100%",
                                        background: getScoreColor(analysis.score),
                                        transition: "width 0.8s ease"
                                    }}
                                />
                            </div>
                        </div>

                        <Section title="Required Keywords from JD" theme={theme}>
                            {analysis.requiredKeywords?.length > 0 ? (
                                analysis.requiredKeywords.map((item, index) => (
                                    <span key={index} style={tagStyle(theme.mutedTagBg, theme.mutedTagText)}>
                    {item}
                  </span>
                                ))
                            ) : (
                                <EmptyText text="No job-description keywords extracted." theme={theme} />
                            )}
                        </Section>

                        <Section title="Matched Skills" theme={theme}>
                            {analysis.matchedSkills?.length > 0 ? (
                                analysis.matchedSkills.map((item, index) => (
                                    <span key={index} style={tagStyle(theme.matchedBg, theme.matchedText)}>
                    {item}
                  </span>
                                ))
                            ) : (
                                <EmptyText text="No matched skills found." theme={theme} />
                            )}
                        </Section>

                        <Section title="Missing Skills" theme={theme}>
                            {analysis.missingSkills?.length > 0 ? (
                                analysis.missingSkills.map((item, index) => (
                                    <span key={index} style={tagStyle(theme.missingBg, theme.missingText)}>
                    {item}
                  </span>
                                ))
                            ) : (
                                <EmptyText text="No missing skills." theme={theme} />
                            )}
                        </Section>

                        <Section title="AI Explanation" theme={theme}>
                            <p style={{ margin: 0, color: theme.subText, lineHeight: 1.6 }}>
                                {getAiExplanation()}
                            </p>
                        </Section>

                        <Section title="Suggestions" theme={theme}>
                            {analysis.suggestions?.length > 0 ? (
                                <ul style={{ margin: 0, paddingLeft: "20px", color: theme.subText, lineHeight: 1.8 }}>
                                    {analysis.suggestions.map((item, index) => (
                                        <li key={index}>{item}</li>
                                    ))}
                                </ul>
                            ) : (
                                <EmptyText text="No suggestions." theme={theme} />
                            )}
                        </Section>
                    </div>
                )}
            </div>
        </div>
    );
}

function InfoCard({ title, value, theme }) {
    return (
        <div
            style={{
                background: theme.sectionBg,
                border: `1px solid ${theme.border}`,
                borderRadius: "16px",
                padding: "18px"
            }}
        >
            <p style={{ margin: 0, fontSize: "13px", color: theme.subText }}>{title}</p>
            <h3 style={{ margin: "8px 0 0 0" }}>{value}</h3>
        </div>
    );
}

function Section({ title, children, theme }) {
    return (
        <div
            style={{
                background: theme.sectionBg,
                border: `1px solid ${theme.border}`,
                borderRadius: "16px",
                padding: "18px",
                marginBottom: "16px"
            }}
        >
            <h3 style={{ marginTop: 0 }}>{title}</h3>
            <div style={{ display: "flex", flexWrap: "wrap", alignItems: "flex-start" }}>
                {children}
            </div>
        </div>
    );
}

function EmptyText({ text, theme }) {
    return <p style={{ margin: 0, color: theme.subText }}>{text}</p>;
}

export default App;
